class Solution:
    def solve(self, products: list[int]) -> list[tuple[str, int]]:
        # Define the SQL query to extract unique product categories and their counts
        query = "SELECT category, COUNT(*) as count FROM products GROUP BY category ORDER BY count DESC";
        # Execute the query and return the result
        import sqlite3
        conn = sqlite3.connect(':memory:')
        c = conn.cursor()
        c.execute(query)
        result = c.fetchall()
        return result;
